<?php
require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();$pdo=db();$stats=['nilai'=>0,'prestasi'=>0,'badge'=>0,'sertifikat'=>0];$top=[];$recent=[];if($pdo){foreach(['nilai'=>'nilai','prestasi'=>'prestasi','badge'=>'badge','sertifikat'=>'sertifikat'] as $k=>$t){$stats[$k]=(int)$pdo->query("SELECT COUNT(*) FROM $t")->fetchColumn();}$top=$pdo->query("SELECT u.id,u.nama,u.username,COUNT(n.id) total_aktivitas,COALESCE(ROUND(AVG(n.skor)),0) rata,COALESCE(MAX(n.skor),0) terbaik FROM users u JOIN nilai n ON n.user_id=u.id WHERE u.role='siswa' GROUP BY u.id ORDER BY rata DESC,total_aktivitas DESC LIMIT 10")->fetchAll();$recent=$pdo->query('SELECT n.*,u.nama FROM nilai n LEFT JOIN users u ON u.id=n.user_id ORDER BY n.id DESC LIMIT 10')->fetchAll();}
$adminPageTitle='Prestasi Siswa';$adminPageDescription='Pantau nilai, badge, dan pencapaian siswa.';$adminActive='prestasi';include __DIR__.'/../../includes/admin_header.php';
?>
<section class="admin-grid"><div class="admin-stat sun"><span class="admin-stat-icon">⭐</span><strong><?=$stats['nilai']?></strong><span>Nilai tersimpan</span></div><div class="admin-stat"><span class="admin-stat-icon">🏆</span><strong><?=$stats['prestasi']?></strong><span>Prestasi</span></div><div class="admin-stat mint"><span class="admin-stat-icon">🎖️</span><strong><?=$stats['badge']?></strong><span>Badge</span></div><div class="admin-stat coral"><span class="admin-stat-icon">📜</span><strong><?=$stats['sertifikat']?></strong><span>Sertifikat</span></div></section>
<div class="admin-columns"><section class="admin-card"><div class="admin-card-head"><div><h2>Peringkat Siswa</h2><p>Berdasarkan rata-rata skor yang tersimpan.</p></div></div><?php if($top):?><div class="admin-table-wrap"><table><thead><tr><th>#</th><th>Siswa</th><th>Aktivitas</th><th>Rata-rata</th><th>Terbaik</th></tr></thead><tbody><?php foreach($top as $i=>$r):?><tr><td><strong><?= $i+1 ?></strong></td><td><a href="<?=url('admin/user/detail.php?id='.$r['id'])?>"><strong><?=e($r['nama'])?></strong><br><small>@<?=e($r['username'])?></small></a></td><td><?=$r['total_aktivitas']?></td><td><?=$r['rata']?></td><td><?=$r['terbaik']?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="admin-empty"><span>🏆</span><strong>Belum ada peringkat</strong><small>Nilai siswa akan membentuk peringkat otomatis.</small></div><?php endif;?></section><section class="admin-card"><div class="admin-card-head"><div><h2>Nilai Terbaru</h2><p>Aktivitas yang baru selesai.</p></div></div><?php if($recent):?><div class="activity-list"><?php foreach($recent as $r):?><div class="activity-item"><span class="activity-icon">⭐</span><span><strong><?=e($r['nama']?:'Pengguna dihapus')?></strong><small><?=e($r['jenis'])?> · <?=e(format_date_id($r['created_at']))?></small></span><span class="score"><?=$r['skor']?></span></div><?php endforeach;?></div><?php else:?><div class="admin-empty"><span>⭐</span><strong>Belum ada nilai</strong></div><?php endif;?></section></div>
<?php include __DIR__.'/../../includes/admin_footer.php'; ?>
